        pad_y, stride_x, stride_y, out_offset, in_offset, act_min, act_max,
        out_tensor_dim_x, out_tensor_dim_y, is_bias_null);

    //test-7 (for tiling-tiling path with even row)
    in_tensor_batch = 1;
    stride_x = 3;
    stride_y = 2;
    in_tensor_dim_x = 57;
    in_tensor_dim_y = 33;
    in_tensor_ch = 1031;
    out_tensor_ch = 5;
    out_tensor_dim_x = 19;
    out_tensor_dim_y = 17;
