2889→
2890→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2891→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V4);
2892→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V20, NDS_VEC_V6);
