int32_t nn_mat_mult_nt_t_s8_v2(const int8_t *lhs,
            const int8_t *rhs,
            const int32_t *bias,
            int8_t *dst,
            const int32_t *dst_multipliers,
            const int32_t *dst_shifts,
            const int32_t lhs_rows,
            const int32_t rhs_rows,
            const int32_t rhs_cols,
            const int32_t lhs_offset,    //value is in the range of [-127, 128]
            const int32_t dst_offset,    //value is in the range of [-128, 127]
            const int32_t activation_min,
            const int32_t activation_max,
            const int32_t lhs_cols_offset,
            int32_t *contri_buf)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
    long vl;
    long rhs_rows_idx = 0;
    long max_vl_per_vg_e8m1, max_vl_per_vg_e8m2, max_vl_per_vg_e8m8;
    NDS_VEC_VSETVLI(max_vl_per_vg_e8m1, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VSETVLI(max_vl_per_vg_e8m2, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
    NDS_VEC_VSETVLI(max_vl_per_vg_e8m8, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);

    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum

    for (rhs_rows_idx = 0; (rhs_rows_idx + 4) <= rhs_rows; rhs_rows_idx += 4)
    {
        const int8_t *lhs_ptr = &lhs[0];
        int8_t       *dst_ptr = &dst[0];

        //load the extra contribution
        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        int32_t *pContri_buf = &contri_buf[rhs_rows_idx];
        NDS_VEC_VLE32_V(NDS_VEC_V28, pContri_buf);

        //load the quantization parameters
        int32_t *shift_ptr = (int32_t *)&dst_shifts[rhs_rows_idx];
        int32_t *mult_ptr  = (int32_t *)&dst_multipliers[rhs_rows_idx];
        NDS_VEC_VLE32_V(NDS_VEC_V24, shift_ptr);
        NDS_VEC_VLE32_V(NDS_VEC_V26, mult_ptr);
        NDS_VEC_VRSUB_VX(NDS_VEC_V24, NDS_VEC_V24, 30);

        long lhs_rows_idx = lhs_rows >> 2;
        while (lhs_rows_idx)
        {
            const int8_t *rhs_ptr = &rhs[0];
            int8_t *rhs_ptr2 = (int8_t *)&rhs_ptr[rhs_cols];
            int8_t *rhs_ptr3 = (int8_t *)&rhs_ptr[rhs_cols * 2];
            int8_t *rhs_ptr4 = (int8_t *)&rhs_ptr[rhs_cols * 3];
            int8_t *lhs_ptr2 = (int8_t *)&lhs_ptr[lhs_cols_offset];
            int8_t *lhs_ptr3 = (int8_t *)&lhs_ptr[lhs_cols_offset * 2];
            int8_t *lhs_ptr4 = (int8_t *)&lhs_ptr[lhs_cols_offset * 3];
            long rhs_cols2 = rhs_cols;

            NDS_VEC_VSETVLI(vl, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //clear v0~v15 (keep mac results)
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

            while(rhs_cols2 >= max_vl_per_vg_e8m1)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
                NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
                NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
                NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
                NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
                NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
                NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
                rhs_cols2 -= vl;
                rhs_ptr += vl;
                rhs_ptr2 += vl;
                rhs_ptr3 += vl;
                rhs_ptr4 += vl;
                lhs_ptr += vl;
                lhs_ptr2 += vl;
                lhs_ptr3 += vl;
                lhs_ptr4 += vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V20, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1, NDS_VEC_V20, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V20, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3, NDS_VEC_V20, NDS_VEC_V19);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V21, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5, NDS_VEC_V21, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6, NDS_VEC_V21, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7, NDS_VEC_V21, NDS_VEC_V19);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V22, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9, NDS_VEC_V22, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V22, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V22, NDS_VEC_V19);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V23, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V23, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V23, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V23, NDS_VEC_V19);
            }
            while(rhs_cols2 > 0)
            {
                //clean one of the sources
                long tmp_vl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
                NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
                NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
                NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);

                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
                NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
                NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
                NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
                NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
                NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
                NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
                rhs_cols2 -= vl;
                rhs_ptr += vl;
                rhs_ptr2 += vl;
                rhs_ptr3 += vl;
                rhs_ptr4 += vl;
                lhs_ptr += vl;
                lhs_ptr2 += vl;
                lhs_ptr3 += vl;
                lhs_ptr4 += vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V20, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1, NDS_VEC_V20, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V20, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3, NDS_VEC_V20, NDS_VEC_V19);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V21, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5, NDS_VEC_V21, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6, NDS_VEC_V21, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7, NDS_VEC_V21, NDS_VEC_V19);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V22, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9, NDS_VEC_V22, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V22, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V22, NDS_VEC_V19);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V23, NDS_VEC_V16);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V23, NDS_VEC_V17);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V23, NDS_VEC_V18);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V23, NDS_VEC_V19);
            }

            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);    //note the avl here
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V1, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V2, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V3, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V4, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V5, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V6, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V7, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V4, NDS_VEC_V8, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V9, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V5, NDS_VEC_V10, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V11, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V6, NDS_VEC_V12, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V13, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V7, NDS_VEC_V14, NDS_VEC_V31);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V15, NDS_VEC_V31);

            //Note. the codes of this section will work correctly only as VLEN>=128b
            NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V16, 1);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1,  2);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V17, 3);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V18, 1);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V3,  2);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V19, 3);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V20, 1);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V5,  2);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V21, 3);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V22, 1);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V7,  2);
            NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V23, 3);

            // add extra contribution back
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);
            NDS_VEC_VADD_VV(NDS_VEC_V2, NDS_VEC_V2, NDS_VEC_V28);
            NDS_VEC_VADD_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V28);
            NDS_VEC_VADD_VV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V28);

            //===== Quantize down =====
            NDS_VEC_VWMUL_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V26);
            NDS_VEC_VWMUL_VV(NDS_VEC_V12, NDS_VEC_V2, NDS_VEC_V26);
            NDS_VEC_VWMUL_VV(NDS_VEC_V16, NDS_VEC_V4, NDS_VEC_V26);
            NDS_VEC_VWMUL_VV(NDS_VEC_V20, NDS_VEC_V6, NDS_VEC_V26);

            NDS_VEC_VNSRA_WV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);
            NDS_VEC_VNSRA_WV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V24);
            NDS_VEC_VNSRA_WV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
            NDS_VEC_VNSRA_WV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V24);

            NDS_VEC_VSSRA_VI(NDS_VEC_V8, NDS_VEC_V8, 1);
            NDS_VEC_VSSRA_VI(NDS_VEC_V12, NDS_VEC_V12, 1);
            NDS_VEC_VSSRA_VI(NDS_VEC_V16, NDS_VEC_V16, 1);
            NDS_VEC_VSSRA_VI(NDS_VEC_V20, NDS_VEC_V20, 1);

            // Add offset
            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, dst_offset);
            NDS_VEC_VADD_VX(NDS_VEC_V12, NDS_VEC_V12, dst_offset);
            NDS_VEC_VADD_VX(NDS_VEC_V16, NDS_VEC_V16, dst_offset);
            NDS_VEC_VADD_VX(NDS_VEC_V20, NDS_VEC_V20, dst_offset);

            // Clamp the result
            NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, activation_min);
            NDS_VEC_VMIN_VX(NDS_VEC_V8, NDS_VEC_V8, activation_max);
            NDS_VEC_VMAX_VX(NDS_VEC_V12, NDS_VEC_V12, activation_min);
            NDS_VEC_VMIN_VX(NDS_VEC_V12, NDS_VEC_V12, activation_max);
            NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, activation_min);
            NDS_VEC_VMIN_VX(NDS_VEC_V16, NDS_VEC_V16, activation_max);
            NDS_VEC_VMAX_VX(NDS_VEC_V20, NDS_VEC_V20, activation_min);
            NDS_VEC_VMIN_VX(NDS_VEC_V20, NDS_VEC_V20, activation_max);

            //narrowing and store the results
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VNSRA_VI(NDS_VEC_V12, NDS_VEC_V12, 0);
            NDS_VEC_VNSRA_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VNSRA_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VNSRA_VI(NDS_VEC_V12, NDS_VEC_V12, 0);
            NDS_VEC_VNSRA_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VNSRA_VI(NDS_VEC_V20, NDS_VEC_V20, 0);

            NDS_VEC_VSE8_V(NDS_VEC_V8, dst_ptr);
            dst_ptr += rhs_rows;
            NDS_VEC_VSE8_V(NDS_VEC_V12, dst_ptr);
            dst_ptr += rhs_rows;
            NDS_VEC_VSE8_V(NDS_VEC_V16, dst_ptr);
            dst_ptr += rhs_rows;
            NDS_VEC_VSE8_V(NDS_VEC_V20, dst_ptr);
            dst_ptr += rhs_rows;
            lhs_ptr -= rhs_cols;
            lhs_ptr += 4 * lhs_cols_offset;
            lhs_rows_idx--;
        }

        // Left-over rows
        long rest_lhs_row = lhs_rows & 3;
        while(rest_lhs_row-- > 0)
        {
            const int8_t *rhs_ptr = &rhs[0];
            int8_t *rhs_ptr2 = (int8_t *)&rhs_ptr[rhs_cols];
            int8_t *rhs_ptr3 = (int8_t *)&rhs_ptr[rhs_cols * 2];
            int8_t *rhs_ptr4 = (int8_t *)&rhs_ptr[rhs_cols * 3];
            long rhs_cols2 = rhs_cols;

            //init
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
            //clear v12~v18 (keep mac results)
            NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
            NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0x0);
